// Consumidor SQS con long polling
ReceiveMessageRequest req = ReceiveMessageRequest.builder()
    .queueUrl(queueUrl)
    .maxNumberOfMessages(10)
    .waitTimeSeconds(20)  // <-- long polling
    .build();

List<Message> messages = sqs.receiveMessage(req).messages();
for (Message msg : messages) {
    processMessage(msg);
    sqs.deleteMessage(b -> b.queueUrl(queueUrl)
                           .receiptHandle(msg.receiptHandle()));
}

@CircuitBreaker(name = "inventoryService", fallbackMethod = "fallback")
public Inventory getInventory(String productId) {
    return inventoryClient.findById(productId);
}

public Inventory fallback(String productId, Exception ex) {
    return Inventory.unavailable(productId); // respuesta degradada
}

