@Transactional
public void createOrder(Order order) {
    orderRepo.save(order);          // 1. guarda entidad
    outboxRepo.save(new OutboxEvent( // 2. guarda evento
        "ORDER_CREATED", order.getId()));
    // SQS se publica FUERA de la transacción
}

